# Bug report
When I started to create a Select component, I received the mentioned error. The app will load but the moment React tries to render the component with the select, it throws this error

## Current behavior

I am running this component in an Nx Monorepo shared lib, 1 app consumes this library and renders 2 instances of the Select element.

Nx version 22.0.3
Rolldown-Vite 7.2.4
Typescript: 5.9.3
Node: 25.1.0
Pnpm: 10.21.0

Provide a clear and concise description of the current behavior you're experiencing. If applicable, provide screenshots and/or videos.

import { Select } from '@base-ui-components/react/select';
import type { FormikProps } from 'formik';
import {
  forwardRef,
  memo,
  useCallback,
  type ChangeEvent,
  type ComponentPropsWithRef,
  type ReactElement,
  type Ref,
} from 'react';
import type { BtgDropDownStyles } from '../types/types';
import styles from './btg_dropdown.module.css';
import BtgError from './error/error';

interface BtgDropDownProps<T>
  extends ComponentPropsWithRef<Exclude<'select', 'style'>> {
  name: Extract<keyof T, string>;
  label: string;
  formik: FormikProps<T>;
  StyleOverrides?: BtgDropDownStyles;
}

const BtgDropDown_ = memo(
  forwardRef(function <T>(
    { name, label, formik, StyleOverrides, ...props }: BtgDropDownProps<T>,
    ref?: Ref<HTMLInputElement> | undefined,
  ) {
    const { value, onChange } = formik.getFieldProps(name);

    const passedOnChange = props.onChange;

    const touched = formik.touched[name] as boolean;
    const error = formik.errors[name] as string;

    const handleChange = useCallback(
      (event: ChangeEvent<HTMLSelectElement>) => {
        onChange(event);
        passedOnChange && passedOnChange(event);
      },
      [onChange, passedOnChange],
    );

    return (
      // <>HELLO</>
      <Select.Root
        inputRef={ref}
        name={name}
        value={value}
        onValueChange={handleChange}
      >
        <Select.GroupLabel
          className={styles['groupLabel']}
          style={StyleOverrides?.GroupLabel}
        >
          {label}
        </Select.GroupLabel>
        <Select.Group className={styles['group']} style={StyleOverrides?.Group}>
          <Select.List className={styles['list']} style={StyleOverrides?.List}>
            <Select.ItemText
              className={styles['itemList']}
              style={StyleOverrides?.ItemText}
            ></Select.ItemText>
            <Select.ItemText
              className={styles['itemList']}
              style={StyleOverrides?.ItemText}
            ></Select.ItemText>
          </Select.List>
          <BtgError touched={touched} error={error} />
        </Select.Group>
      </Select.Root>
    );
  }),
);

BtgDropDown_.displayName = 'BtgDropDown';

export const BtgDropDown = BtgDropDown_ as unknown as <T>(
  props: BtgDropDownProps<T> & { ref?: Ref<HTMLSelectElement> },
) => ReactElement<T>;

export default BtgDropDown;


